import{_ as e,a,b as r,c as o,d}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"إضافة قناة OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/onedrive.md","filePath":"ar-SA/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"ar-SA/upload/onedrive.md"};function p(h,t,m,b,u,f){return n(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="إضافة-قناة-onedrive" tabindex="-1">إضافة قناة OneDrive <a class="header-anchor" href="#إضافة-قناة-onedrive" aria-label="Permalink to &quot;إضافة قناة OneDrive&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-أولًا؟" tabindex="-1">ما الذي تحتاجه أولًا؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-أولًا؟" aria-label="Permalink to &quot;ما الذي تحتاجه أولًا؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>لماذا تحتاجه</th></tr></thead><tbody><tr><td>حساب Microsoft</td><td>للوصول إلى صفحات إدارة Microsoft وتفويض OneDrive</td></tr><tr><td>نطاق ImgBed الخاص بك</td><td>لاستخدامه في OAuth callback URL</td></tr><tr><td>App registration</td><td>لإنشاء <code>Client ID</code> و <code>Client Secret</code></td></tr><tr><td>حساب OneDrive</td><td>موقع التخزين الفعلي للملفات</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="الخطوة-1-افتح-microsoft-entra-id" tabindex="-1">الخطوة 1: افتح Microsoft Entra ID <a class="header-anchor" href="#الخطوة-1-افتح-microsoft-entra-id" aria-label="Permalink to &quot;الخطوة 1: افتح Microsoft Entra ID&quot;">​</a></h3><ol><li>افتح <code>portal.azure.com</code>.</li><li>ابحث في الأعلى عن <code>Microsoft Entra ID</code>.</li><li>إذا لم تظهر الصفحة المطلوبة في القائمة، اختر:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>افتح <code>Microsoft Entra ID</code>.</li><li>افتح <code>App registrations</code>.</li><li>اضغط <code>New registration</code>.</li></ol><h3 id="الخطوة-2-سجّل-تطبيقًا" tabindex="-1">الخطوة 2: سجّل تطبيقًا <a class="header-anchor" href="#الخطوة-2-سجّل-تطبيقًا" aria-label="Permalink to &quot;الخطوة 2: سجّل تطبيقًا&quot;">​</a></h3><p>في صفحة <code>New registration</code> املأ:</p><table tabindex="0"><thead><tr><th>الحقل</th><th>ما الذي تدخله</th></tr></thead><tbody><tr><td>Name</td><td>اسم واضح، مثل <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>اختر حسب الجدول أدناه</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>إرشاد لاختيار نوع الحساب:</p><table tabindex="0"><thead><tr><th>حالتك</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>OneDrive شخصي فقط</td><td>اختر خيار حساب Microsoft الشخصي.</td></tr><tr><td>حسابات شخصية وحسابات عمل/تعليم</td><td>اختر الخيار الذي يدعم الحسابات الشخصية والتنظيمية.</td></tr><tr><td>OneDrive شركة أو مدرسة فقط</td><td>اختر خيار الحساب التنظيمي.</td></tr></tbody></table><p>بعد ملء النموذج اضغط register.</p><p><img src="'+e+'" alt="إنشاء OneDrive app" loading="lazy"></p><h3 id="الخطوة-3-انسخ-معلومات-التطبيق" tabindex="-1">الخطوة 3: انسخ معلومات التطبيق <a class="header-anchor" href="#الخطوة-3-انسخ-معلومات-التطبيق" aria-label="Permalink to &quot;الخطوة 3: انسخ معلومات التطبيق&quot;">​</a></h3><p>بعد إنشاء التطبيق انسخ هذه القيم من صفحة overview:</p><table tabindex="0"><thead><tr><th>حقل Microsoft</th><th>حقل ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> للحسابات التنظيمية</td></tr></tbody></table><p><img src="'+a+'" alt="Application و tenant IDs" loading="lazy"></p><h3 id="الخطوة-4-أنشئ-client-secret" tabindex="-1">الخطوة 4: أنشئ Client Secret <a class="header-anchor" href="#الخطوة-4-أنشئ-client-secret" aria-label="Permalink to &quot;الخطوة 4: أنشئ Client Secret&quot;">​</a></h3><ol><li>افتح <code>Certificates &amp; secrets</code>.</li><li>اضغط <code>New client secret</code>.</li><li>أدخل أي وصف مناسب.</li><li>اختر مدة الانتهاء.</li><li>انسخ <code>Value</code> فور إنشائه.</li></ol><p><img src="'+r+'" alt="حفظ قيمة client secret" loading="lazy"></p><h3 id="الخطوة-5-أضف-api-permissions" tabindex="-1">الخطوة 5: أضف API Permissions <a class="header-anchor" href="#الخطوة-5-أضف-api-permissions" aria-label="Permalink to &quot;الخطوة 5: أضف API Permissions&quot;">​</a></h3><ol><li>افتح <code>API permissions</code>.</li><li>اضغط <code>Add a permission</code>.</li><li>اختر <code>Microsoft Graph</code>.</li><li>اختر <code>Delegated permissions</code>.</li><li>أضف الصلاحيات التالية:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>الغرض</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>رفع الملفات وإنشاء المجلدات وحذف الملفات</td></tr><tr><td><code>offline_access</code></td><td>يسمح لـ ImgBed بالحصول على <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>قراءة معلومات الحساب والحصة</td></tr></tbody></table><h3 id="الخطوة-6-املأ-قناة-onedrive" tabindex="-1">الخطوة 6: املأ قناة OneDrive <a class="header-anchor" href="#الخطوة-6-املأ-قناة-onedrive" aria-label="Permalink to &quot;الخطوة 6: املأ قناة OneDrive&quot;">​</a></h3><p>في إعدادات الرفع اختر <code>OneDrive</code> واملأ:</p><table tabindex="0"><thead><tr><th>حقل ImgBed</th><th>ما الذي تدخله</th></tr></thead><tbody><tr><td>Channel name</td><td>اسم واضح، مثل <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>قيمة <code>Client Secret Value</code> التي نسختها</td></tr><tr><td>Tenant ID</td><td>استخدم الجدول أدناه</td></tr><tr><td>Refresh Token</td><td>اتركه فارغًا الآن</td></tr><tr><td>Root directory</td><td>اختياري. الافتراضي <code>imgbed</code>.</td></tr><tr><td>Note</td><td>اختياري</td></tr></tbody></table><p><img src="'+o+'" alt="ملء إعداد قناة OneDrive" loading="lazy"></p><p>طريقة ملء <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>نوع الحساب الذي اخترته</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>المنظمة الحالية فقط</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="الخطوة-7-احصل-على-refresh-token" tabindex="-1">الخطوة 7: احصل على Refresh Token <a class="header-anchor" href="#الخطوة-7-احصل-على-refresh-token" aria-label="Permalink to &quot;الخطوة 7: احصل على Refresh Token&quot;">​</a></h3><ol><li>في ImgBed اضغط <code>Get Token</code>.</li><li>سجّل الدخول بحساب Microsoft الذي تريد ربطه.</li><li>وافق على طلب التفويض.</li><li>ستعرض صفحة callback قيمة <code>Refresh Token</code>.</li><li>انسخها.</li><li>ارجع إلى ImgBed والصقها في حقل <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="نسخ refresh token" loading="lazy"></p><h3 id="الخطوة-8-احفظ-القناة" tabindex="-1">الخطوة 8: احفظ القناة <a class="header-anchor" href="#الخطوة-8-احفظ-القناة" aria-label="Permalink to &quot;الخطوة 8: احفظ القناة&quot;">​</a></h3><p>بعد ملء جميع الحقول احفظ القناة.</p><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح portal.azure.com</span></span>
<span class="line"><span>-&gt; ابحث عن Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; افتح App registrations</span></span>
<span class="line"><span>-&gt; سجّل app جديد</span></span>
<span class="line"><span>-&gt; املأ Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; انسخ Application (client) ID</span></span>
<span class="line"><span>-&gt; تحقق من callback URL في Authentication</span></span>
<span class="line"><span>-&gt; أنشئ Client Secret في Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; أضف permissions في API permissions</span></span>
<span class="line"><span>-&gt; أدخل Client ID / Client Secret / Tenant ID في ImgBed</span></span>
<span class="line"><span>-&gt; اضغط Get Token</span></span>
<span class="line"><span>-&gt; انسخ Refresh Token من صفحة callback</span></span>
<span class="line"><span>-&gt; الصقه في ImgBed واحفظ</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const D=i(c,[["render",p]]);export{v as __pageData,D as default};
